/**
 * @name ShortcutConfigurable getValue processes route filter/predicate args as SpEL
 * @description The entryValue parameter in ShortcutConfigurable.getValue is passed to SpEL parseExpression without sanitization
 * @kind path-problem
 * @problem.severity error
 * @id java/shortcut-configurable-spel-path
 * @tags security
 *       external/cwe/cwe-917
 */

import java
import semmle.code.java.dataflow.TaintTracking

module ShortcutSpELConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // The entryValue parameter of ShortcutConfigurable.getValue
    exists(Method m, Parameter p |
      m.getDeclaringType().hasQualifiedName("org.springframework.cloud.gateway.support", "ShortcutConfigurable") and
      m.hasName("getValue") and
      p = m.getAParameter() and
      p.getName() = "entryValue" |
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("parseExpression") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName(
        "org.springframework.expression", "ExpressionParser") |
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module ShortcutSpELFlow = TaintTracking::Global<ShortcutSpELConfig>;
import ShortcutSpELFlow::PathGraph

from ShortcutSpELFlow::PathNode source, ShortcutSpELFlow::PathNode sink
where ShortcutSpELFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "ShortcutConfigurable entryValue flows to SpEL parseExpression from $@.", source.getNode(), "entryValue parameter"

/**
 * @name Full taint: HTTP request body through RouteDefinition args to ShortcutConfigurable SpEL
 * @description Traces user HTTP input through route filter/predicate args to SpEL evaluation via ShortcutConfigurable.getValue
 * @kind path-problem
 * @problem.severity error
 * @id java/http-to-shortcut-spel
 * @tags security
 *       external/cwe/cwe-917
 *       external/cwe/cwe-094
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module HttpToShortcutSpELConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // ShortcutConfigurable.getValue entryValue parameter
    exists(MethodCall mc |
      mc.getMethod().hasName("getValue") and
      mc.getMethod().getDeclaringType().hasQualifiedName(
        "org.springframework.cloud.gateway.support", "ShortcutConfigurable") |
      sink.asExpr() = mc.getArgument(2)
    )
    or
    // Direct SpEL parseExpression
    exists(MethodCall mc |
      mc.getMethod().hasName("parseExpression") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName(
        "org.springframework.expression", "ExpressionParser") |
      sink.asExpr() = mc.getArgument(0)
    )
  }

  predicate isAdditionalFlowStep(DataFlow::Node n1, DataFlow::Node n2) {
    exists(MethodCall mc |
      mc.getMethod().hasName("getFilters") or
      mc.getMethod().hasName("getPredicates") or
      mc.getMethod().hasName("getArgs") or
      mc.getMethod().hasName("values") or
      mc.getMethod().hasName("get") |
      n1.asExpr() = mc.getQualifier() and n2.asExpr() = mc
    )
  }
}

module HttpToShortcutSpELFlow = TaintTracking::Global<HttpToShortcutSpELConfig>;
import HttpToShortcutSpELFlow::PathGraph

from HttpToShortcutSpELFlow::PathNode source, HttpToShortcutSpELFlow::PathNode sink
where HttpToShortcutSpELFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "HTTP input flows to SpEL evaluation from $@.", source.getNode(), "remote flow source"

/**
 * @name ConfigurationService bind - taint from route definition args to SpEL
 * @description ConfigurationService.bind() receives route filter/predicate args map and passes values to ShortcutConfigurable for SpEL evaluation
 * @kind path-problem
 * @problem.severity error
 * @id java/config-service-bind-to-spel
 * @tags security
 *       external/cwe/cwe-917
 *       external/cwe/cwe-094
 */

import java
import semmle.code.java.dataflow.TaintTracking

module ConfigServiceSpELConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Parameters of ConfigurationService methods that take args maps
    exists(Method m |
      m.getDeclaringType().hasQualifiedName(
        "org.springframework.cloud.gateway.support", "ConfigurationService") and
      (m.hasName("bind") or m.hasName("with")) |
      source.asParameter() = m.getAParameter()
    )
    or
    // getArgs() calls - the map of filter/predicate arguments from route definitions
    exists(MethodCall mc |
      mc.getMethod().hasName("getArgs") |
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("parseExpression") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName(
        "org.springframework.expression", "ExpressionParser") |
      sink.asExpr() = mc.getArgument(0)
    )
  }

  predicate isAdditionalFlowStep(DataFlow::Node n1, DataFlow::Node n2) {
    exists(MethodCall mc |
      mc.getMethod().hasName("values") or
      mc.getMethod().hasName("get") or
      mc.getMethod().hasName("entrySet") or
      mc.getMethod().hasName("getValue") |
      n1.asExpr() = mc.getQualifier() and n2.asExpr() = mc
    )
  }
}

