/**
 * @name Actuator createRoute endpoint accepts RouteDefinition with filter args flowing to SpEL
 * @description The actuator createRoute/save endpoint accepts a RouteDefinition body that flows through
 *              RouteDefinitionRouteLocator into ConfigurationService and ultimately SpEL parseExpression
 * @kind path-problem
 * @problem.severity error
 * @id java/actuator-create-route-spel
 * @tags security
 *       external/cwe/cwe-917
 *       external/cwe/cwe-094
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ActuatorCreateRouteSpELConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // AbstractGatewayControllerEndpoint POST methods (createRoute, save)
    exists(Method m |
      m.getDeclaringType().getASupertype*().hasQualifiedName(
        "org.springframework.cloud.gateway.actuate", "AbstractGatewayControllerEndpoint") and
      (m.hasName("createRoute") or m.hasName("save") or m.hasName("refreshRoutes") or
       m.getName().toLowerCase().matches("%route%") or m.getName().toLowerCase().matches("%filter%")) |
      source.asParameter() = m.getAParameter()
    )
    or
    // Also any remote flow source
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("parseExpression") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName(
        "org.springframework.expression", "ExpressionParser") |
      sink.asExpr() = mc.getArgument(0)
    )
  }

  predicate isAdditionalFlowStep(DataFlow::Node n1, DataFlow::Node n2) {
    // RouteDefinition -> getFilters/getPredicates -> FilterDefinition -> getArgs -> values -> SpEL
    exists(MethodCall mc |
      mc.getMethod().hasName("getFilters") or mc.getMethod().hasName("getPredicates") or
      mc.getMethod().hasName("getArgs") or mc.getMethod().hasName("values") or
      mc.getMethod().hasName("get") or mc.getMethod().hasName("save") or
      mc.getMethod().hasName("convertRouteDefinition") |
      n1.asExpr() = mc.getQualifier() and n2.asExpr() = mc
    )
    or
    // RouteDefinitionWriter.save -> locator -> getRouteDefinitions
    exists(MethodCall mc |
      mc.getMethod().hasName("save") |
      n1.asExpr() = mc.getAnArgument() and n2.asExpr() = mc
    )
  }
}

