/**
 * @name CVE-2022-22947: RouteDefinition save() body to SpEL injection
 * @description The actuator save(RouteDefinition) endpoint accepts a JSON body that is
 *              later processed through ConfigurationService into SpEL parseExpression,
 *              enabling remote code execution via SpEL injection
 * @kind path-problem
 * @problem.severity error
 * @id java/cve-2022-22947-route-spel
 * @tags security
 *       external/cwe/cwe-917
 *       external/cwe/cwe-094
 */

import java
import semmle.code.java.dataflow.TaintTracking

module SaveRouteSpELConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // save(RouteDefinition route) - the body parameter from HTTP POST
    exists(Method m, Parameter p |
      m.getDeclaringType().getASupertype*().hasQualifiedName(
        "org.springframework.cloud.gateway.actuate", "AbstractGatewayControllerEndpoint") and
      m.hasName("save") and
      p = m.getAParameter() and
      p.getType().getName() = "RouteDefinition" |
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("parseExpression") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName(
        "org.springframework.expression", "ExpressionParser") |
      sink.asExpr() = mc.getArgument(0)
    )
  }

  predicate isAdditionalFlowStep(DataFlow::Node n1, DataFlow::Node n2) {
    // Mono.just(route) -> route stored in RouteDefinitionWriter
    exists(MethodCall mc |
      mc.getMethod().hasName("just") |
      n1.asExpr() = mc.getAnArgument() and n2.asExpr() = mc
    )
    or
    // RouteDefinitionWriter.save(routeMono)
    exists(MethodCall mc |
      mc.getMethod().hasName("save") |
      n1.asExpr() = mc.getAnArgument() and n2.asExpr() = mc
    )
    or
    // getFilters / getPredicates / getArgs / values / get
    exists(MethodCall mc |
      mc.getMethod().hasName("getFilters") or mc.getMethod().hasName("getPredicates") or
      mc.getMethod().hasName("getArgs") or mc.getMethod().hasName("values") or
      mc.getMethod().hasName("get") or mc.getMethod().hasName("getRouteDefinitions") or
      mc.getMethod().hasName("flatMap") or mc.getMethod().hasName("map") |
      n1.asExpr() = mc.getQualifier() and n2.asExpr() = mc
    )
  }
}

